import{_ as a,c as t,o as p,a5 as e}from"./chunks/framework.DwbewbAn.js";const r="/assets/image-20220125005640549.BQoeqyFP.png",o="/assets/image-20220125005725068.DMnVY_LN.png",s="/assets/image-20220125005806358.BTpVF5gV.png",i="/assets/v2-d3ab3e41c76aa233f5cd4898bc9e819e_720w.C3FoBCh0.jpg",n="/assets/v2-6545c63fd96653762ff8f1aede55af88_720w.Dc69VUIK.jpg",l="/assets/v2-641aa0e76f3b71b910b8ab24690b99a7_720w.BJ7ahRrY.jpg",g="/assets/v2-8dbd6df21f447c429591bee8908d9a3f_720w.CaSEw1kG.jpg",h="/assets/v2-d1eede6566db099096f10a6110c88a60_720w._VwRarZe.jpg",c="/assets/v2-287bd6d80d2abe73b881b5d14fa1266e_720w.uv2OVjea.jpg",d="/assets/v2-29b67989052ce95d03e852141022b122_720w.B2sFwiQw.jpg",m="/assets/v2-115e5daca9acd5c709f1e0666ebc3233_720w.CIPF1Liy.jpg",S="/assets/v2-3faa978370cff2d026e3e4a3110eed11_720w.DrtpWu-Z.jpg",_="/assets/v2-dbe5665c2c4f226a94feb02c408f01e7_720w.D0Hj9gc1.jpg",b="/assets/v2-e1cef1b5d0317c687198a3a4f55888a5_720w.BWpxI6Ay.jpg",u="/assets/v2-5e3a0cdb68d164c4bfd47f688fb44e49_720w.jEGespxs.jpg",T="/assets/v2-5eebc428d05c59c300dd65c274e608a6_720w.BALyEkBF.jpg",A="/assets/v2-01dac738ef5307753e69b95708a254f1_720w.QrjoJs1R.jpg",j=JSON.parse('{"title":"HTTPS","description":"","frontmatter":{},"headers":[],"relativePath":"doc/网络协议/HTTPS/https.md","filePath":"packages/doc/src/网络协议/HTTPS/https.md","lastUpdated":1704643216000}'),f={name:"doc/网络协议/HTTPS/https.md"},C=e('<h1 id="https" tabindex="-1">HTTPS <a class="header-anchor" href="#https" aria-label="Permalink to &quot;HTTPS&quot;">​</a></h1><h2 id="_1-作用" tabindex="-1">1.作用 <a class="header-anchor" href="#_1-作用" aria-label="Permalink to &quot;1.作用&quot;">​</a></h2><h3 id="_1-http-由于是明文传输-所以安全上存在以下三个风险" tabindex="-1">1.HTTP 由于是明文传输，所以安全上存在以下三个风险： <a class="header-anchor" href="#_1-http-由于是明文传输-所以安全上存在以下三个风险" aria-label="Permalink to &quot;1.HTTP 由于是明文传输，所以安全上存在以下三个风险：&quot;">​</a></h3><p><strong>窃听风险</strong>，比如通信链路上可以获取通信内容，用户号容易没。</p><p><strong>篡改风险</strong>，比如强制植入垃圾广告，视觉污染，用户眼容易瞎。</p><p><strong>冒充风险</strong>，比如冒充淘宝网站，用户钱容易没。</p><h3 id="_2-https-在-http-与-tcp-层之间加入了-ssl-tls-协议-可以很好的解决了上述的风险" tabindex="-1">2.HTTP<strong>S</strong> 在 HTTP 与 TCP 层之间加入了 SSL/TLS 协议，可以很好的解决了上述的风险： <a class="header-anchor" href="#_2-https-在-http-与-tcp-层之间加入了-ssl-tls-协议-可以很好的解决了上述的风险" aria-label="Permalink to &quot;2.HTTP**S** 在 HTTP 与 TCP 层之间加入了 SSL/TLS 协议，可以很好的解决了上述的风险：&quot;">​</a></h3><p><strong>信息加密</strong>：交互信息无法被窃取，但你的号会因为「自身忘记」账号而没。</p><p><strong>校验机制</strong>：无法篡改通信内容，篡改了就不能正常显示，但百度「竞价排名」依然可以搜索垃圾</p><p>广告。</p><p><strong>身份证书</strong>：证明淘宝是真的淘宝网，但你的钱还是会因为「剁手」而没。</p><p>可见，只要自身不做「恶」，SSL/TLS 协议是能保证通信是安全的。</p><h3 id="_3-https-是如何解决上面的三个风险的" tabindex="-1">3.HTTPS 是如何解决上面的三个风险的？ <a class="header-anchor" href="#_3-https-是如何解决上面的三个风险的" aria-label="Permalink to &quot;3.HTTPS 是如何解决上面的三个风险的？&quot;">​</a></h3><p><strong>混合加密</strong>的方式实现信息的<strong>机密性</strong>，解决了窃听的风险。</p><p><strong>摘要算法</strong>的方式来实现<strong>完整性</strong>，它能够为数据生成独一无二的「指纹」，指纹用于校验数据的完</p><p>整性，解决了篡改的风险。</p><p>将服务器公钥放入到<strong>数字证书</strong>中，解决了冒充的风险。</p><h3 id="_1-混合加密" tabindex="-1"><em>1.</em> 混合加密 <a class="header-anchor" href="#_1-混合加密" aria-label="Permalink to &quot;*1.* 混合加密&quot;">​</a></h3><p>通过<strong>混合加密</strong>的方式可以保证信息的<strong>机密性</strong>，解决了窃听的风险。</p><p><img src="'+r+'" alt="image-20220125005640549"></p><p>HTTPS 采用的是<strong>对称加密</strong>和<strong>非对称加密</strong>结合的「混合加密」方式：</p><p>在通信建立前采用<strong>非对称加密</strong>的方式交换「会话秘钥」，后续就不再使用非对称加密。</p><p>在通信过程中全部使用<strong>对称加密</strong>的「会话秘钥」的方式加密明文数据。</p><p>采用「混合加密」的方式的原因：</p><p><strong>对称加密</strong>只使用一个密钥，运算速度快，密钥必须保密，无法做到安全的密钥交换。</p><p><strong>非对称加密</strong>使用两个密钥：公钥和私钥，公钥可以任意分发而私钥保密，解决了密钥交换问题但</p><p>速度慢。</p><h3 id="_2-摘要算法" tabindex="-1">2.摘要算法 <a class="header-anchor" href="#_2-摘要算法" aria-label="Permalink to &quot;2.摘要算法&quot;">​</a></h3><p><strong>摘要算法</strong>用来实现<strong>完整性</strong>，能够为数据生成独一无二的「指纹」，用于校验数据的完整性，解决了篡改</p><p>的风险。</p><p><img src="'+o+'" alt="image-20220125005725068"></p><p>客户端在发送明文之前会通过摘要算法算出明文的「指纹」，发送的时候把「指纹 + 明文」一同加密成</p><p>密文后，发送给服务器，服务器解密后，用相同的摘要算法算出发送过来的明文，通过比较客户端携带</p><p>的「指纹」和当前算出的「指纹」做比较，若「指纹」相同，说明数据是完整的。</p><h3 id="_3-数字证书" tabindex="-1">3.数字证书 <a class="header-anchor" href="#_3-数字证书" aria-label="Permalink to &quot;3.数字证书&quot;">​</a></h3><p>客户端先向服务器端索要公钥，然后用公钥加密信息，服务器收到密文后，用自己的私钥解密。</p><p>这就存在些问题，如何保证公钥不被篡改和信任度？</p><p>所以这里就需要借助第三方权威机构 CA （数字证书认证机构），将<strong>服务器公钥放在数字证书</strong>（由数</p><p>字证书认证机构颁发）中，只要证书是可信的，公钥就是可信的。</p><p><img src="'+s+'" alt="image-20220125005806358"></p><p>通过数字证书的方式保证服务器公钥的身份，解决冒充的风险。</p><p>SSL/TLS 协议建立的详细流程：</p><p><em>1. ClientHello</em></p><p>首先，由客户端向服务器发起加密通信请求，也就是 ClientHello 请求。</p><p>在这一步，客户端主要向服务器发送以下信息：</p><p>（1）客户端支持的 SSL/TLS 协议版本，如 TLS 1.2 版本。</p><p>（2）客户端生产的随机数（ Client Random ），后面用于生产「会话秘钥」。</p><p>（3）客户端支持的密码套件列表，如 RSA 加密算法。</p><p><em>2. SeverHello</em></p><p>服务器收到客户端请求后，向客户端发出响应，也就是 SeverHello 。服务器回应的内容有如下内容：</p><p>（1）确认 SSL/ TLS 协议版本，如果浏览器不支持，则关闭加密通信。</p><p>（2）服务器生产的随机数（ Server Random ），后面用于生产「会话秘钥」。</p><p>（3）确认的密码套件列表，如 RSA 加密算法。</p><p>（4）服务器的数字证书。</p><p>*3.*客户端回应</p><p>客户端收到服务器的回应之后，首先通过浏览器或者操作系统中的 CA 公钥，确认服务器的数字证书的</p><p>真实性。</p><p>如果证书没有问题，客户端会从数字证书中取出服务器的公钥，然后使用它加密报文，向服务器发送如</p><p>下信息：</p><p>（1）一个随机数（ pre-master key ）。该随机数会被服务器公钥加密。</p><p>（2）加密通信算法改变通知，表示随后的信息都将用「会话秘钥」加密通信。</p><p>（3）客户端握手结束通知，表示客户端的握手阶段已经结束。这一项同时把之前所有内容的发生的数</p><p>据做个摘要，用来供服务端校验。</p><p>上面第一项的随机数是整个握手阶段的第三个随机数，这样服务器和客户端就同时有三个随机数，接着</p><p>就用双方协商的加密算法，<strong>各自生成</strong>本次通信的「会话秘钥」。</p><p><em>4.</em> 服务器的最后回应</p><p>服务器收到客户端的第三个随机数（ pre-master key ）之后，通过协商的加密算法，计算出本次通信的</p><p>「会话秘钥」。然后，向客户端发生最后的信息：</p><p>（1）加密通信算法改变通知，表示随后的信息都将用「会话秘钥」加密通信。（2）服务器握手结束通知，表示服务器的握手阶段已经结束。这一项同时把之前所有内容的发生的数</p><p>据做个摘要，用来供客户端校验。</p><p>至此，整个 SSL/TLS 的握手阶段全部结束。接下来，客户端与服务器进入加密通信，就完全是使用普</p><p>通的 HTTP 协议，只不过用「会话秘钥」加密内容。</p><h2 id="_2-概念" tabindex="-1">2.概念 <a class="header-anchor" href="#_2-概念" aria-label="Permalink to &quot;2.概念&quot;">​</a></h2><h4 id="_1-摘要" tabindex="-1">1.摘要 <a class="header-anchor" href="#_1-摘要" aria-label="Permalink to &quot;1.摘要&quot;">​</a></h4><p>一段信息，经过摘要算法得到一串哈希值，就是摘要(dijest)。</p><p>信息是任意长度，而摘要是定长。</p><p>摘要算法有MD5、SHA1、SHA256、SHA512等，算法把无限的映射成有限，因此可能会有碰撞（两个不同的信息，算出的摘要相同）</p><p>摘要不同于加密算法，因为不存在解密，只不过从摘要反推原信息很难（可以认为能加密但无法解密还原，但可以用于比对）。类比到人的话：时间一直向前走 ，我没有办法从现在的你身上反观到你过去的样子，也没法从现在的他身上反观到他过去的样子……但你们现在的样子依然有作用，那就是在于“是否相同”：我可以通过比对现在的你和现在的他是否相同，来判断过去的你和他是否相同，而无需知道过去的你和过去的他具体是什么样子。</p><p>摘要相同，信息一定相同。<strong>如果两张图片的md5相同，说明图片完全一样，不需要重复爬取。</strong></p><p>利用这个特点，摘要还可以用于应用在网站后台数据库中，用于比对用户的<strong>输入密码和预设密码是否相同</strong>。这里都无需关心密码本身是什么，关注的是密码是否相同，而密码是否相同取决于摘要是否相同，所以问题转化成了<strong>摘要是否相同</strong>。将用户密码的摘要而不是密码本身保存在数据库中，因为反推很难，所以真实密码是保密的……非要暴露的话，也是通过比对而不是反推。</p><h4 id="_2-非对称加密算法" tabindex="-1">2.非对称加密算法 <a class="header-anchor" href="#_2-非对称加密算法" aria-label="Permalink to &quot;2.非对称加密算法&quot;">​</a></h4><p>算法重要的概念是公钥和私匙。</p><p>先有私钥，再用函数生成公钥。公钥包含了私钥的信息，但也掺杂了其他随机变量，因此不能反推。</p><p>私匙不要泄露，公钥要告诉和你通信的对方。公钥加密，只有对应私钥能解开（保密）；私钥加密，只有对应公钥能解开（不可抵赖）。</p><p>具体有两种情形：</p><p>（1）对方用你的公钥加密信息，你收到后用私钥解开。</p><p>只有你有私钥，所以只有你能解开，换句话说，有私钥才能看到信息，很安全。</p><p>（2）你拿私钥加密信息，对方收到后用你的公钥解开。</p><p>公钥是公开的，所以其他人也可以看到你的信息，不保密。</p><p>私钥加密，只有对应公钥能解开。既然用你的公钥能解开，说明加密一定是你的私钥。私钥只有你有，所以一定是你发送的，你不可抵赖。</p><h4 id="_3-数字签名" tabindex="-1">3.数字签名 <a class="header-anchor" href="#_3-数字签名" aria-label="Permalink to &quot;3.数字签名&quot;">​</a></h4><p><strong>摘要经过加密，就得到数字签名</strong></p><p>数字签名在发送方，分两步：（1）从内容算摘要（哈希算法）（2）从摘要明文到摘要密文，也称数字签名（发送方私钥+加密算法）</p><p>数字签名验证在接收方，分两步：（1）从摘要密文（数字签名）到摘要明文（发送方公钥+解密算法）（2）从收到的内容当场计算摘要（哈希算法），与（1）的结果比对是否一致</p><p>如果一致，可以说明两点：</p><p>（1）内容未被篡改（摘要一致）</p><p>（2）内容只能是私钥拥方发送，不可抵赖（密文能够用对方的公钥解开）</p><p>然后单独想一下，</p><p>（1）为什么要对摘要加密后再发送？为什么不直接发摘要？摘要不可以逆向推导原文，摘要泄露了也没事……</p><p>答：摘要泄露是没事，但不怀好意的人的目的可能并不在想要窃听你发送了什么，而是想伪造发送的内容让你相信。通过同时替换摘要和内容，很简单就实现了。所以摘要需要经过加密，不怀好意的人没有私钥，无法完成加密。或者说你收到的东西只要能用公钥解密，你才认为这个东西确实是对应私钥持有者完成的。这叫做当事人不可抵赖，同时别人无法仿冒。（数字签名：不可抵赖+无法仿冒）</p><p>（2）为什么不直接对内容加密，而是先生成摘要，对摘要加密？</p><p>答：可能是内容很长吧，直接加密算半天！摘要算法可以把无限长的内容输出成长度固定的摘要，再进行加密时间就是可以预估的</p><h4 id="_4-数字证书" tabindex="-1">4.<strong>数字证书</strong> <a class="header-anchor" href="#_4-数字证书" aria-label="Permalink to &quot;4.**数字证书**&quot;">​</a></h4><p>上面的一切都很完美，你用公钥能够解密，说明确实是私钥方发送的，你很放心……</p><p>但有没有想过，万一这把公钥本身，就被人做了手脚？？？</p><p>为了保证“公钥”是可信的，数字证书应运而生。</p><p>数字证书里有个重要概念，CA,发送方先把自己的公钥给CA，CA对其进行加密得到加密后的发送方公钥（用的是CA的私钥和CA加密算法），也就是CA的数字证书。</p><p>注意这里有两个不同的非对称算法（对应2个公钥私钥对），一个算法是发送方加密摘要的，用于生成数字签名；另一个算法是CA加密发送方公钥的，用于生成数字证书。两个算法相互独立，没有必然联系。</p><p>发送时不仅发送内容、数字签名，还包含发送方的数字证书。接收方拿到后，首先从数字证书中解密出发送方公钥（用的是CA的公钥和CA解密算法），这个公钥必然是可信的。然后就是和前面一样的流程，拿发送方公钥去解密数字证书，得到摘要；最后比对摘要是否一致。</p><p>一个问题：既然数字证书是为了保证发送方公钥不是别人伪造的，那怎么保证“CA”的公钥不是伪造的呢？</p><p>答：CA是第三方机构，CA公钥是公开的，接收方可以跟别人比对（比如在网上查询），因此不可能伪造。但是发送方公钥，接收方是通过通信得到的，收到后无法验证。</p><h2 id="_3-tls握手" tabindex="-1">3.TLS握手 <a class="header-anchor" href="#_3-tls握手" aria-label="Permalink to &quot;3.TLS握手&quot;">​</a></h2><p><img src="'+i+'" alt=""></p><p>上图简要概述来 TLS 的握手过程，其中每一个「框」都是一个记录（<em>record</em>），记录是 TLS 收发数据的基本单位，类似于 TCP 里的 segment。多个记录可以组合成一个 TCP 包发送，所以<strong>通常经过「四个消息」就可以完成 TLS 握手，也就是需要 2个 RTT 的时延</strong>，然后就可以在安全的通信环境里发送 HTTP 报文，实现 HTTPS 协议。</p><p>所以可以发现，HTTPS 是应用层协议，需要先完成 TCP 连接建立，然后走 TLS 握手过程后，才能建立通信安全的连接。</p><p>事实上，不同的密钥交换算法，TLS 的握手过程可能会有一些区别。</p><p>这里先简单介绍下密钥交换算法，因为考虑到性能的问题，所以双方在加密应用信息时使用的是对称加密密钥，而对称加密密钥是不能被泄漏的，为了保证对称加密密钥的安全性，所以使用非对称加密的方式来保护对称加密密钥的协商，这个工作就是密钥交换算法负责的。</p><h3 id="tls-第一次握手" tabindex="-1">TLS 第一次握手 <a class="header-anchor" href="#tls-第一次握手" aria-label="Permalink to &quot;TLS 第一次握手&quot;">​</a></h3><p>客户端首先会发一个「<strong>Client Hello</strong>」消息，字面意思我们也能理解到，这是跟服务器「打招呼」。</p><p><img src="'+n+'" alt="img"></p><p>消息里面有客户端使用的 TLS 版本号、支持的密码套件列表，以及生成的<strong>随机数（*Client Random*）</strong>，这个随机数会被服务端保留，它是生成对称加密密钥的材料之一。</p><h3 id="tls-第二次握手" tabindex="-1">TLS 第二次握手 <a class="header-anchor" href="#tls-第二次握手" aria-label="Permalink to &quot;TLS 第二次握手&quot;">​</a></h3><p>当服务端收到客户端的「Client Hello」消息后，会确认 TLS 版本号是否支持，和从密码套件列表中选择一个密码套件，以及生成<strong>随机数（*Server Random*）</strong>。</p><p>接着，返回「<strong>Server Hello</strong>」消息，消息里面有服务器确认的 TLS 版本号，也给出了随机数（Server Random），然后从客户端的密码套件列表选择了一个合适的密码套件。</p><p><img src="'+l+'" alt="img"></p><p>可以看到，服务端选择的密码套件是 “Cipher Suite: TLS_RSA_WITH_AES_128_GCM_SHA256”。</p><p>这个密码套件看起来真让人头晕，好一大串，但是其实它是有固定格式和规范的。基本的形式是「<strong>密钥交换算法 + 签名算法 + 对称加密算法 + 摘要算法</strong>」， 一般 WITH 单词前面有两个单词，第一个单词是约定密钥交换的算法，第二个单词是约定证书的验证算法。比如刚才的密码套件的意思就是：</p><ul><li>由于 WITH 单词只有一个 RSA，则说明握手时密钥交换算法和签名算法都是使用 RSA；</li><li>握手后的通信使用 AES 对称算法，密钥长度 128 位，分组模式是 GCM；</li><li>摘要算法 SHA384 用于消息认证和产生随机数；</li></ul><p>就前面这两个客户端和服务端相互「打招呼」的过程，客户端和服务端就已确认了 TLS 版本和使用的密码套件，而且你可能发现客户端和服务端都会各自生成一个随机数，并且还会把随机数传递给对方。</p><p>那这个随机数有啥用呢？其实这两个随机数是后续作为生成「会话密钥」的条件，所谓的会话密钥就是数据传输时，所使用的对称加密密钥。</p><p>然后，服务端为了证明自己的身份，会发送「<strong>Server Certificate</strong>」给客户端，这个消息里含有数字证书。</p><p><img src="'+g+'" alt="img"></p><p>随后，服务端发了「<strong>Server Hello Done</strong>」消息，目的是告诉客户端，我已经把该给你的东西都给你了，本次打招呼完毕。</p><p><img src="'+h+'" alt="img"></p><h3 id="客户端验证证书" tabindex="-1">客户端验证证书 <a class="header-anchor" href="#客户端验证证书" aria-label="Permalink to &quot;客户端验证证书&quot;">​</a></h3><p>在这里刹个车，客户端拿到了服务端的数字证书后，要怎么校验该数字证书是真实有效的呢？</p><h3 id="数字证书和-ca-机构" tabindex="-1">数字证书和 CA 机构 <a class="header-anchor" href="#数字证书和-ca-机构" aria-label="Permalink to &quot;数字证书和 CA 机构&quot;">​</a></h3><p>在说校验数字证书是否可信的过程前，我们先来看看数字证书是什么，一个数字证书通常包含了：</p><ul><li>公钥；</li><li>持有者信息；</li><li>证书认证机构（CA）的信息；</li><li>CA 对这份文件的数字签名及使用的算法；</li><li>证书有效期；</li><li>还有一些其他额外信息；</li></ul><p>那数字证书的作用，是用来认证公钥持有者的身份，以防止第三方进行冒充。说简单些，证书就是用来告诉客户端，该服务端是否是合法的，因为只有证书合法，才代表服务端身份是可信的。</p><p>我们用证书来认证公钥持有者的身份（服务端的身份），那证书又是怎么来的？又该怎么认证证书呢？</p><p>为了让服务端的公钥被大家信任，服务端的证书都是由 CA （<em>Certificate Authority</em>，证书认证机构）签名的，CA 就是网络世界里的公安局、公证中心，具有极高的可信度，所以由它来给各个公钥签名，信任的一方签发的证书，那必然证书也是被信任的。</p><p>之所以要签名，是因为签名的作用可以避免中间人在获取证书时对证书内容的篡改。</p><h3 id="数字证书签发和验证流程" tabindex="-1">数字证书签发和验证流程 <a class="header-anchor" href="#数字证书签发和验证流程" aria-label="Permalink to &quot;数字证书签发和验证流程&quot;">​</a></h3><p>如下图图所示，为数字证书签发和验证流程：</p><p><img src="'+c+'" alt="img"></p><p>CA 签发证书的过程，如上图左边部分：</p><ul><li>首先 CA 会把持有者的公钥、用途、颁发者、有效时间等信息打成一个包，然后对这些信息进行 Hash 计算，得到一个 Hash 值；</li><li>然后 CA 会使用自己的私钥将该 Hash 值加密，生成 Certificate Signature，也就是 CA 对证书做了签名；</li><li>最后将 Certificate Signature 添加在文件证书上，形成数字证书；</li></ul><p>客户端校验服务端的数字证书的过程，如上图右边部分：</p><ul><li>首先客户端会使用同样的 Hash 算法获取该证书的 Hash 值 H1；</li><li>通常浏览器和操作系统中集成了 CA 的公钥信息，浏览器收到证书后可以使用 CA 的公钥解密 Certificate Signature 内容，得到一个 Hash 值 H2 ；</li><li>最后比较 H1 和 H2，如果值相同，则为可信赖的证书，否则则认为证书不可信。</li></ul><h3 id="证书链" tabindex="-1">证书链 <a class="header-anchor" href="#证书链" aria-label="Permalink to &quot;证书链&quot;">​</a></h3><p>但事实上，证书的验证过程中还存在一个证书信任链的问题，因为我们向 CA 申请的证书一般不是根证书签发的，而是由中间证书签发的，比如百度的证书，从下图你可以看到，证书的层级有三级：</p><p><img src="'+d+'" alt="img"></p><p>对于这种三级层级关系的证书的验证过程如下：</p><ul><li>客户端收到 <a href="https://link.zhihu.com/?target=http%3A//baidu.com/" target="_blank" rel="noreferrer">baidu.com</a> 的证书后，发现这个证书的签发者不是根证书，就无法根据本地已有的根证书中的公钥去验证 <a href="https://link.zhihu.com/?target=http%3A//baidu.com/" target="_blank" rel="noreferrer">baidu.com</a> 证书是否可信。于是，客户端根据 <a href="https://link.zhihu.com/?target=http%3A//baidu.com/" target="_blank" rel="noreferrer">baidu.com</a> 证书中的签发者，找到该证书的颁发机构是 “GlobalSign Organization Validation CA - SHA256 - G2”，然后向 CA 请求该中间证书。</li><li>请求到证书后发现 “GlobalSign Organization Validation CA - SHA256 - G2” 证书是由 “GlobalSign Root CA” 签发的，由于 “GlobalSign Root CA” 没有再上级签发机构，说明它是根证书，也就是自签证书。应用软件会检查此证书有否已预载于根证书清单上，如果有，则可以利用根证书中的公钥去验证 “GlobalSign Organization Validation CA - SHA256 - G2” 证书，如果发现验证通过，就认为该中间证书是可信的。</li><li>“GlobalSign Organization Validation CA - SHA256 - G2” 证书被信任后，可以使用 “GlobalSign Organization Validation CA - SHA256 - G2” 证书中的公钥去验证 <a href="https://link.zhihu.com/?target=http%3A//baidu.com/" target="_blank" rel="noreferrer">baidu.com</a> 证书的可信性，如果验证通过，就可以信任 <a href="https://link.zhihu.com/?target=http%3A//baidu.com/" target="_blank" rel="noreferrer">baidu.com</a> 证书。</li></ul><p>在这四个步骤中，最开始客户端只信任根证书 GlobalSign Root CA 证书的，然后 “GlobalSign Root CA” 证书信任 “GlobalSign Organization Validation CA - SHA256 - G2” 证书，而 “GlobalSign Organization Validation CA - SHA256 - G2” 证书又信任 <a href="https://link.zhihu.com/?target=http%3A//baidu.com/" target="_blank" rel="noreferrer">baidu.com</a> 证书，于是客户端也信任 <a href="https://link.zhihu.com/?target=http%3A//baidu.com/" target="_blank" rel="noreferrer">baidu.com</a>证书。</p><p>总括来说，由于用户信任 GlobalSign，所以由 GlobalSign 所担保的 <a href="https://link.zhihu.com/?target=http%3A//baidu.com/" target="_blank" rel="noreferrer">baidu.com</a> 可以被信任，另外由于用户信任操作系统或浏览器的软件商，所以由软件商预载了根证书的 GlobalSign 都可被信任。</p><p><img src="'+m+'" alt="img"></p><p>操作系统里一般都会内置一些根证书，比如我的 MAC 电脑里内置的根证书有这么多：</p><p><img src="'+S+'" alt="img"></p><p>这样的一层层地验证就构成了一条信任链路，整个证书信任链验证流程如下图所示：</p><p><img src="'+_+'" alt="img"></p><p>最后一个问题，为什么需要证书链这么麻烦的流程？Root CA 为什么不直接颁发证书，而是要搞那么多中间层级呢？</p><p>这是为了确保根证书的绝对安全性，将根证书隔离地越严格越好，不然根证书如果失守了，那么整个信任链都会有问题。</p><h3 id="tls-第三次握手" tabindex="-1">TLS 第三次握手 <a class="header-anchor" href="#tls-第三次握手" aria-label="Permalink to &quot;TLS 第三次握手&quot;">​</a></h3><p>客户端验证完证书后，认为可信则继续往下走。接着，客户端就会生成一个新的<strong>随机数 (*pre-master*)</strong>，用服务器的 RSA 公钥加密该随机数，通过「<strong>Change Cipher Key Exchange</strong>」消息传给服务端。</p><p><img src="'+b+'" alt="img"></p><p>服务端收到后，用 RSA 私钥解密，得到客户端发来的随机数 (pre-master)。</p><p>至此，<strong>客户端和服务端双方都共享了三个随机数，分别是 Client Random、Server Random、pre-master</strong>。</p><p>于是，双方根据已经得到的三个随机数，生成<strong>会话密钥（Master Secret）</strong>，它是对称密钥，用于对后续的 HTTP 请求/响应的数据加解密。</p><p>生成完会话密钥后，然后客户端发一个「<strong>Change Cipher Spec</strong>」，告诉服务端开始使用加密方式发送消息。</p><p><img src="'+u+'" alt="img"></p><p>然后，客户端再发一个「<strong>Encrypted Handshake Message（Finishd）</strong>」消息，把之前所有发送的数据做个摘要，再用会话密钥（master secret）加密一下，让服务器做个验证，验证加密通信是否可用和之前握手信息是否有被中途篡改过。</p><p><img src="'+T+'" alt="img"></p><p>可以发现，「Change Cipher Spec」之前传输的 TLS 握手数据都是明文，之后都是对称密钥加密的密文。</p><h3 id="tls-第四次握手" tabindex="-1">TLS 第四次握手 <a class="header-anchor" href="#tls-第四次握手" aria-label="Permalink to &quot;TLS 第四次握手&quot;">​</a></h3><p>服务器也是同样的操作，发「<strong>Change Cipher Spec</strong>」和「<strong>Encrypted Handshake Message</strong>」消息，如果双方都验证加密和解密没问题，那么握手正式完成。</p><p>最后，就用「会话密钥」加解密 HTTP 请求和响应了。</p><h2 id="_4-rsa-算法的缺陷" tabindex="-1">4.### RSA 算法的缺陷 <a class="header-anchor" href="#_4-rsa-算法的缺陷" aria-label="Permalink to &quot;4.### RSA 算法的缺陷&quot;">​</a></h2><p><strong>使用 RSA 密钥协商算法的最大问题是不支持前向保密</strong>。因为客户端传递随机数（用于生成对称加密密钥的条件之一）给服务端时使用的是公钥加密的，服务端收到到后，会用私钥解密得到随机数。所以一旦服务端的私钥泄漏了，过去被第三方截获的所有 TLS 通讯密文都会被破解。</p><p>为了解决这一问题，于是就有了 DH 密钥协商算法，这里简单介绍它的工作流程。</p><p><img src="'+A+'" alt="img"></p><p>客户端和服务端各自会生成随机数，并以此作为私钥，然后根据公开的 DH 计算公示算出各自的公钥，通过 TLS 握手双方交换各自的公钥，这样双方都有自己的私钥和对方的公钥，然后双方根据各自持有的材料算出一个随机数，这个随机数的值双方都是一样的，这就可以作为后续对称加密时使用的密钥。</p><p>DH 密钥交换过程中，<strong>即使第三方截获了 TLS 握手阶段传递的公钥，在不知道的私钥的情况下，也是无法计算出密钥的，而且每一次对称加密密钥都是实时生成的，实现前向保密</strong>。</p><p>但因为 DH 算法的计算效率问题，后面出现了 ECDHE 密钥协商算法，我们现在大多数网站使用的正是 ECDHE 密钥协商算法，关于 ECDHE 握手的过程，将在下一篇揭晓，尽情期待哦。</p>',185),H=[C];function P(k,q,L,x,R,v){return p(),t("div",null,H)}const w=a(f,[["render",P]]);export{j as __pageData,w as default};
